<?php
namespace App\Services\Admin;
use App\Models\{Booking,Passenger,TravelSchedule}; use Illuminate\Support\Arr; use Illuminate\Support\Facades\DB;
class BookingService { public function __construct(private SeatService $seats, private PnrService $pnr, private QRService $qr) {} public function create(array $data, ?int $userId=null): Booking { return DB::transaction(function() use($data,$userId){ $schedule=TravelSchedule::lockForUpdate()->findOrFail($data['travel_schedule_id']); $seatIds=$data['seat_ids']; $this->seats->releaseExpiredHolds(); $this->seats->validateAvailable($schedule,$seatIds,$data['hold_token'] ?? null); $passenger=Passenger::create(Arr::only($data,['first_name','last_name','gender','dob','nationality_id','passport','national_id','contact_number'])); $total=($schedule->base_fare + $schedule->route->charges()->sum('amount')) * count($seatIds); $booking=Booking::create(['pnr'=>$this->pnr->generate(),'passenger_id'=>$passenger->id,'travel_route_id'=>$schedule->travel_route_id,'travel_schedule_id'=>$schedule->id,'return_schedule_id'=>$data['return_schedule_id'] ?? null,'created_by'=>$userId,'travel_date'=>$schedule->departure_at->toDateString(),'return_date'=>$data['return_date'] ?? null,'status'=>'confirmed','total_amount'=>$total]); foreach($seatIds as $seatId) $booking->seats()->attach($seatId,['travel_schedule_id'=>$schedule->id]); $this->seats->consumeHold($schedule,$seatIds,$data['hold_token'] ?? null); $booking->update(['qr_code'=>$this->qr->generate($booking)]); return $booking->refresh(); }); } }
